class Solution:
    def maxProduct(self, nums: List[int], k: int, limit: int) -> int:
        # The maximum possible absolute alternating sum is 150 * 12 = 1800.
        # We use an offset to map negative sums to non-negative indices.
        offset = 1800
        max_idx = 3600  # Covers range [-1800, 1800]

        # dp[parity][sum_idx] stores the maximum product for a subsequence
        # with length parity (0 for even, 1 for odd) and alternating sum = sum_idx - offset.
        # Initialize with -1 to represent unreachable states.
        dp = [[-1] * (max_idx + 1) for _ in range(2)]

        for x in nums:
            # Create a copy for the next state to avoid using the same element multiple times in one step
            new_dp = [row[:] for row in dp]

            for parity in range(2):
                # If current subsequence has even length (parity 0), next element is added (+)
                # If current subsequence has odd length (parity 1), next element is subtracted (-)
                sign = 1 if parity == 0 else -1

                for s_idx in range(max_idx + 1):
                    prod = dp[parity][s_idx]
                    if prod == -1:
                        continue

                    new_prod = prod * x
                    if new_prod <= limit:
                        new_s_idx = s_idx + sign * x
                        if 0 <= new_s_idx <= max_idx:
                            if new_prod > new_dp[1 - parity][new_s_idx]:
                                new_dp[1 - parity][new_s_idx] = new_prod

            # Start a new subsequence with the current element x
            # This corresponds to a subsequence of length 1 (parity 1), sum x, product x
            if x <= limit:
                s_idx = offset + x
                if 0 <= s_idx <= max_idx:
                    if x > new_dp[1][s_idx]:
                        new_dp[1][s_idx] = x

            dp = new_dp

        # Check if k is within the possible range of alternating sums
        if abs(k) > 1800:
            return -1

        target_idx = offset + k
        ans = max(dp[0][target_idx], dp[1][target_idx])

        return ans if ans != -1 else -1
